(9708,4437,657,'Tiiswalt, Mart; Tiiswald, Mart',80,4,1911,NULL,'Vanus viiside juures: 70 (80?). Tekstikogus on kaks Mart Tiisvaldi - üks 80 a. (EÜS VIII 739 (339) - 744/5 (343), Sargvere laulud") ja teine 70 a., (alates 745 (344)). Lk 745 on märkus: "Mart Tiiswald, teise Mardiga onupojad, 70 aastat vana, Paluvalla laulud". Geni andmetel on 2 Mart Tiisvaldi, nende isad Hans ja Tõnno on vennad. Viisikoguja näikse kirjeldavat ühtainsat inimest (lk 505). Siinse laulu puhul oletasin, et viis ja tekst on eri Martidelt. [T. S.]"'),
(9709,2439,657,'Tiiswalt, Mart; Tiiswald, Mart',80,4,1911,NULL,'Vanus viiside juures: 70 (80?). Tekstikogus on kaks Mart Tiisvaldi - üks 80 a. (EÜS VIII 739 (339) - 744/5 (343), Sargvere laulud") ja teine 70 a., (alates 745 (344)). Lk 745 on märkus: "Mart Tiiswald, teise Mardiga onupojad, 70 aastat vana, Paluvalla laulud". Geni andmetel on 2 Mart Tiisvaldi, nende isad Hans ja Tõnno on vennad. Viisikoguja näikse kirjeldavat ühtainsat inimest (lk 505). Siinse laulu puhul oletasin, et viis ja tekst on eri Martidelt. [T. S.]"'),
(9710,2436,657,'Tiiswalt, Mart; Tiiswald, Mart',80,4,1911,NULL,'Vanus viiside juures: 70 (80?). Tekstikogus on kaks Mart Tiisvaldi - üks 80 a. (EÜS VIII 739 (339) - 744/5 (343), Sargvere laulud") ja teine 70 a., (alates 745 (344)). Lk 745 on märkus: "Mart Tiiswald, teise Mardiga onupojad, 70 aastat vana, Paluvalla laulud". Geni andmetel on 2 Mart Tiisvaldi, nende isad Hans ja Tõnno on vennad. Viisikoguja näikse kirjeldavat ühtainsat inimest (lk 505). Siinse laulu puhul oletasin, et viis ja tekst on eri Martidelt. [T. S.]"'),
