(12380,4148,NULL,NULL,64,4,1907,NULL,'Laulik Mäe Ann on nimetatud ainult sõnade kogus (lk 1949), samas kui viis olevat kirjutatud Mihkli kihelkonnast. Siiski tunduvad mõlemad olevat kirjutatud sama esituse järgi ja tekstikogu andmed näivad usaldusväärsemad. [T. S.]'),
(12381,4488,NULL,NULL,64,4,1907,NULL,NULL),
(12382,4149,NULL,NULL,64,4,1907,NULL,'Lauliku nime lisasin oletamisi. Viisi juures on viide Mäe Anne pulmalauluviisile (Vt nr 7.") See on  EÜS IV 1850 (7)), mille sõnu koguja peab laulule nr 28 ilmselt kuuluvaks või sobivaks. Viis on kirjutatud oletatavast Mäe Anne laulust nr 27 järgmiseks. [T. S.]"'),
(12383,4504,NULL,NULL,64,4,1907,NULL,'Viis kooliõpetaja vanematelt. Viisi juures: Vt nr 28, 7." EÜS IV 1850 (7) on pulmalauluviis, millel on ka sõnad, ja koguja peab neid ilmselt samaks."'),
